import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../../../components/layout/Navbar";
import DashboardFooter from "../../../components/layout/DashboardFooter";
import ProfileLayout from "../../../components/profile/ProfileLayout";

export default function UserProfilePage() {
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const userId = localStorage.getItem("userId");
        if (!userId) return;
        const res = await axios.get(`http://localhost:8080/users/${userId}`);
        setUserData(res.data);
      } catch (err) {
        console.error("Failed to load user profile", err);
      } finally {
        setLoading(false);
      }
    };
    fetchUser();
  }, []);

  const handleUpdateProfile = async (payload) => {
    const userId = localStorage.getItem("userId");
    await axios.put(`http://localhost:8080/users/${userId}/profile`, payload);
    setUserData(prev => ({ ...prev, name: payload.name }));
  };

  const handleChangePassword = async (payload) => {
    const userId = localStorage.getItem("userId");
    await axios.post(`http://localhost:8080/users/${userId}/change-password`, payload);
  };

  return (
    <div className="min-h-screen flex flex-col bg-surface relative overflow-x-hidden pt-[80px]">
      <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-primary/5 via-surface to-surface pointer-events-none" />
      <Navbar />
      <main className="flex-1 w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 z-10 relative">
        <ProfileLayout 
          userData={userData}
          role="USER"
          loading={loading}
          onUpdateProfile={handleUpdateProfile}
          onChangePassword={handleChangePassword}
        />
      </main>
      <DashboardFooter />
    </div>
  );
}
